#include <vector>
#include <unordered_set>
#include <algorithm>
using namespace std;

long long solve(long long n, long long k) {
    if (k == 0) {
        return (n >= 1) ? 1 : 0;
    }

    const int M = 1000;
    vector<int> depth_small(M+1, 0);
    vector<vector<int>> sets_by_depth(6);

    depth_small[1] = 0;
    sets_by_depth[0].push_back(1);

    for (int i = 2; i <= M; i++) {
        int popcnt = __builtin_popcount(i);
        depth_small[i] = 1 + depth_small[popcnt];
        if (depth_small[i] < 6) {
            sets_by_depth[depth_small[i]].push_back(i);
        }
    }

    if (n == 0) {
        return 0;
    }
    vector<int> digits;
    long long temp = n;
    while (temp) {
        digits.push_back(temp % 2);
        temp /= 2;
    }
    reverse(digits.begin(), digits.end());
    int len = digits.size();

    unordered_set<int> target;
    for (int num : sets_by_depth[k-1]) {
        if (num <= len) {
            target.insert(num);
        }
    }

    vector<vector<long long>> dp(2, vector<long long>(len+1, 0));
    dp[1][0] = 1;

    for (int i = 0; i < len; i++) {
        vector<vector<long long>> new_dp(2, vector<long long>(len+1, 0));
        for (int tight = 0; tight < 2; tight++) {
            if (tight) {
                int up = digits[i];
                for (int cnt = 0; cnt <= len; cnt++) {
                    if (dp[tight][cnt] == 0) continue;
                    for (int d = 0; d <= up; d++) {
                        int new_tight = (d == up) ? 1 : 0;
                        int new_cnt = cnt + d;
                        if (new_cnt <= len) {
                            new_dp[new_tight][new_cnt] += dp[tight][cnt];
                        }
                    }
                }
            } else {
                for (int cnt = 0; cnt <= len; cnt++) {
                    if (dp[tight][cnt] == 0) continue;
                    for (int d = 0; d <= 1; d++) {
                        int new_tight = 0;
                        int new_cnt = cnt + d;
                        if (new_cnt <= len) {
                            new_dp[new_tight][new_cnt] += dp[tight][cnt];
                        }
                    }
                }
            }
        }
        dp = move(new_dp);
    }

    long long total = 0;
    for (int tight = 0; tight < 2; tight++) {
        for (int cnt = 1; cnt <= len; cnt++) {
            if (target.find(cnt) != target.end()) {
                total += dp[tight][cnt];
            }
        }
    }

    if (k == 1) {
        total--;
        if (total < 0) total = 0;
    }

    return total;
}
```

### Explanation
1. **Precomputation**:
   - We compute the depth for numbers 1 to 1000 and categorize them into sets based on their depth (0 to 5). This helps in quickly determining the target set for depth `k-1` during the digit DP phase.

2. **Digit DP**:
   - The binary representation of `n` is processed from the most significant bit to the least significant bit.
   - The DP state `dp[tight][cnt]` tracks the count of numbers formed so far, where `tight` indicates if the current prefix matches the prefix of `n`, and `cnt` is the number of set bits.
   - For each bit, we consider setting it to 0 or 1, updating the tight constraint and the count of set bits accordingly.

3. **Target Set and Adjustment**:
   - The target set consists of numbers with depth `k-1`, which are used to filter numbers during the DP phase.
   - For `k=1`, the number 1 (which has depth 0) is excluded by subtracting 1 from the total count, as it was included in the digit DP results due to its popcount being in the target set.

This approach efficiently handles the large constraint (n up to 10^15) by leveraging precomputation for small numbers and digit DP for counting valid numbers without explicitly iterating through all numbers up to n.

