using namespace std;

long long count_numbers_with_popcount(long long n, int s) {
    if (s == 0) return 0;
    if (n == 0) return 0;
    vector<int> digits;
    long long num = n;
    while (num) {
        digits.push_back(num & 1);
        num >>= 1;
    }
    if (digits.empty()) {
        return 0;
    }
    reverse(digits.begin(), digits.end());
    int len = digits.size();
    vector<vector<vector<long long>>> dp(len+1, vector<vector<long long>>(2, vector<long long>(len+1, 0)));
    dp[0][1][0] = 1;

    for (int i = 0; i < len; i++) {
        for (int tight = 0; tight < 2; tight++) {
            for (int ones = 0; ones <= i; ones++) {
                if (dp[i][tight][ones] == 0) continue;
                int upper_bound = (tight) ? digits[i] : 1;
                for (int b = 0; b <= upper_bound; b++) {
                    int new_tight = tight && (b == digits[i]);
                    int new_ones = ones + (b == 1);
                    if (new_ones <= len) {
                        dp[i+1][new_tight][new_ones] += dp[i][tight][ones];
                    }
                }
            }
        }
    }
    long long ans = 0;
    for (int tight = 0; tight < 2; tight++) {
        if (s <= len) {
            ans += dp[len][tight][s];
        }
    }
    return ans;
}

long long solve(long long n, long long k) {
    static vector<vector<int>> T_set = []{
        vector<vector<int>> T_set(6);
        vector<int> d(61, 0);
        d[1] = 0;
        for (int i = 2; i <= 60; i++) {
            int cnt = __builtin_popcount(i);
            d[i] = 1 + d[cnt];
        }
        for (int i = 1; i <= 60; i++) {
            if (d[i] < 6) {
                T_set[d[i]].push_back(i);
            }
        }
        return T_set;
    }();

    if (k == 0) {
        if (n >= 1) return 1;
        else return 0;
    }
    if (k > 5) {
        return 0;
    }
    vector<int> targets = T_set[k-1];
    long long total = 0;
    for (int s : targets) {
        total += count_numbers_with_popcount(n, s);
    }
    if (k == 1) {
        total -= 1;
    }
    return total;
}
