#include <vector>
#include <set>
#include <string>
#include <iostream>
#include <algorithm>
using namespace std;

long long countPop(long long n, int t_val) {
    if (t_val == 0) return 0;
    string s = "";
    long long num = n;
    while (num) {
        s = char('0' + (num & 1)) + s;
        num /= 2;
    }
    if (s.empty()) s = "0";
    int len = s.size();
    vector<long long> dp0(t_val + 1, 0);
    vector<long long> dp1(t_val + 1, 0);
    dp1[0] = 1;

    for (int i = 0; i < len; i++) {
        vector<long long> new_dp0(t_val + 1, 0);
        vector<long long> new_dp1(t_val + 1, 0);
        int d = s[i] - '0';

        for (int j = 0; j <= t_val; j++) {
            if (dp0[j] != 0) {
                new_dp0[j] += dp0[j];
                if (j + 1 <= t_val) {
                    new_dp0[j + 1] += dp0[j];
                }
            }
        }

        for (int j = 0; j <= t_val; j++) {
            if (dp1[j] != 0) {
                if (d == 0) {
                    new_dp1[j] += dp1[j];
                } else {
                    new_dp0[j] += dp1[j];
                    if (j + 1 <= t_val) {
                        new_dp1[j + 1] += dp1[j];
                    }
                }
            }
        }

        dp0 = new_dp0;
        dp1 = new_dp1;
    }

    return dp0[t_val] + dp1[t_val];
}

long long solve(long long n, long long k) {
    if (k == 0) {
        return (n >= 1) ? 1 : 0;
    }

    vector<int> dep(61, 0);
    dep[1] = 0;
    for (int i = 2; i <= 60; i++) {
        dep[i] = 1 + dep[__builtin_popcount(i)];
    }

    set<int> T;
    for (int i = 1; i <= 60; i++) {
        if (dep[i] == k - 1) {
            T.insert(i);
        }
    }

    long long ans = 0;
    for (int t : T) {
        ans += countPop(n, t);
    }

    if (k == 1) {
        ans -= 1;
    }

    return ans;
}
