#include <vector>
#include <string>
using namespace std;

long long C[51][51];
int dep[51];

int popcount(int x) {
    int c = 0;
    while (x) {
        c++;
        x = x & (x-1);
    }
    return c;
}

void precompute() {
    for (int i = 0; i <= 50; i++) {
        for (int j = 0; j <= 50; j++) {
            if (j == 0) 
                C[i][j] = 1;
            else if (i == 0)
                C[i][j] = 0;
            else 
                C[i][j] = C[i-1][j-1] + C[i-1][j];
        }
    }

    dep[1] = 0;
    for (int i = 2; i <= 50; i++) {
        int cnt = popcount(i);
        dep[i] = 1 + dep[cnt];
    }
}

long long countWithPop(long long n, int k0) {
    if (k0 == 0) {
        return n >= 0 ? 1 : 0;
    }
    if (n == 0) {
        return 0;
    }
    string s = "";
    long long temp = n;
    while (temp) {
        if (temp & 1) 
            s = '1' + s;
        else
            s = '0' + s;
        temp = temp / 2;
    }
    int L = s.size();

    long long ans = 0;
    int count = 0;
    for (int i = 0; i < L; i++) {
        if (s[i] == '1') {
            int rem = L - i - 1;
            int need = k0 - count;
            if (need >= 0 && rem >= need) {
                ans += C[rem][need];
            }
            count++;
            if (count > k0) 
                break;
        }
    }
    if (count == k0) {
        ans += 1;
    }
    return ans;
}

long long solve(long long n, long long k) {
    static bool precomputed = false;
    if (!precomputed) {
        precompute();
        precomputed = true;
    }

    if (k == 0) {
        return n >= 1 ? 1 : 0;
    }

    vector<int> Y;
    for (int i = 1; i <= 50; i++) {
        if (dep[i] == (int)(k-1)) {
            Y.push_back(i);
        }
    }

    long long ans = 0;
    for (int y : Y) {
        long long cnt = countWithPop(n, y);
        if (y == 1) {
            cnt--;
        }
        ans += cnt;
    }
    return ans;
}
```

### Explanation
1. **Precomputation**:
   - **Pascal's Triangle (C)**: This matrix stores combinations `C(n, k)` for all `0 <= k <= n <= 50`, which helps in efficiently counting numbers with exactly `k` set bits in a range.
   - **Depth Array (dep)**: This array stores the popcount-depth for each integer from 1 to 50. The depth is computed recursively: `depth[i] = 1 + depth[popcount(i)]`, with `depth[1] = 0`.

2. **countWithPop Function**:
   - This function counts numbers in `[0, n]` with exactly `k0` set bits. It uses the binary representation of `n` to traverse each bit, leveraging precomputed combinations to count valid numbers without iterating through each number individually.

3. **solve Function**:
   - For `k = 0`, it returns 1 if `n >= 1` (only the number 1 has depth 0).
   - For `k > 0`, it collects all integers `y` (1-50) with depth `k-1`. For each `y`, it counts numbers in `[1, n]` with exactly `y` set bits, adjusting the count by subtracting 1 if `y = 1` to exclude the number 1 (which has depth 0, not `k`). The total count is summed and returned.

This approach efficiently leverages precomputation and combinatorial mathematics to handle large values of `n` (up to \(10^{15}\)) without resorting to brute-force methods.
